// client/src/components/HistoryList.js
import React from 'react';
import { ListGroup, Badge, Button } from 'react-bootstrap';

const HistoryList = ({ history, onDelete }) => {
  if (!history || history.length === 0) {
    return <p className="text-center text-muted">No previous analyses found</p>;
  }

  // Format the timestamp
  const formatDate = (dateString) => {
    const options = {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  // Get badge variant based on sentiment
  const getBadgeVariant = (sentiment) => {
    switch (sentiment) {
      case 'positive':
        return 'success';
      case 'negative':
        return 'danger';
      default:
        return 'secondary';
    }
  };
  
  // Get type badge info
  const getTypeBadge = (type) => {
    switch (type) {
      case 'emotional':
        return { icon: '❤️', variant: 'primary' };
      case 'date':
        return { icon: '📅', variant: 'info' };
      case 'math':
        return { icon: '🔢', variant: 'warning' };
      case 'historical':
        return { icon: '📚', variant: 'dark' };
      default:
        return { icon: '📝', variant: 'light' };
    }
  };

  return (
    <ListGroup variant="flush">
      {history.map((item) => {
        const typeBadge = getTypeBadge(item.type || 'emotional');
        
        return (
          <ListGroup.Item 
            key={item._id} 
            className="d-flex justify-content-between align-items-start history-item"
          >
            <div className="ms-2 me-auto">
              <div className="fw-bold">
                {item.text.length > 50 ? `${item.text.substring(0, 50)}...` : item.text}
              </div>
              <div className="d-flex mt-1 align-items-center">
                <Badge
                  pill
                  bg={getBadgeVariant(item.sentiment)}
                  className="me-2"
                >
                  {item.sentiment}
                </Badge>
                <Badge 
                  bg={typeBadge.variant} 
                  className="me-2"
                >
                  {typeBadge.icon} {item.type || 'emotional'}
                </Badge>
                <small className="text-muted">{formatDate(item.createdAt)}</small>
              </div>
              {item.explanation && (
                <small className="d-block text-muted mt-1">
                  {item.explanation}
                </small>
              )}
            </div>
            <div className="d-flex align-items-center">
              <span className="me-3">Score: {(item.score * 10).toFixed(2)}</span>
              <Button 
                variant="outline-danger" 
                size="sm"
                onClick={() => onDelete(item._id)}
              >
                &times;
              </Button>
            </div>
          </ListGroup.Item>
        );
      })}
    </ListGroup>
  );
};

export default HistoryList;
